// State machine — tracks each customer's conversation step
const staticData = $getWorkflowStaticData('global');
const customerPhone = $json.body?.from || $json.from;
const text = ($json.body?.text || $json.text || '').trim();

const state = staticData[customerPhone] || { step: 'start' };

return [{ json: { customerPhone, text, state, staticData } }];

// Save customer name, advance to awaiting_address
const staticData = $json.staticData;
const phone = $json.customerPhone;
const name = $json.text;

staticData[phone] = { ...staticData[phone], step: 'awaiting_address', customer_name: name };

return [{ json: {
  to: phone,
  message: `Got it, ${name}! What's your delivery address?`
} }];

// Save address, advance to awaiting_payment
const staticData = $json.staticData;
const phone = $json.customerPhone;

staticData[phone] = { ...staticData[phone], step: 'awaiting_payment', delivery_address: $json.text };

return [{ json: {
  to: phone,
  message: 'How would you like to pay?\n\n1) Bank Transfer\n2) Cash on Delivery (COD)\n\nReply *1* or *2*.'
} }];

const staticData = $json.staticData;
const phone = $json.customerPhone;
const choice = $json.text;
const state = staticData[phone];

const paymentMethod = (choice === '1' || choice.includes('bank')) ? 'bank_transfer' : 'cod';
staticData[phone] = { ...state, step: 'order_placing', payment_method: paymentMethod };

if (paymentMethod === 'bank_transfer') {
  return [{ json: {
    to: phone,
    message: `Please transfer PKR ${state.total} to:\n\nBank: HBL\nAccount: 1234-5678-9012\nName: Ahmed Khan\n\nSend screenshot after transfer.`,
    state: staticData[phone],
    do_save_order: true
  } }];
} else {
  return [{ json: {
    to: phone,
    message: null,
    state: staticData[phone],
    do_save_order: true
  } }];
}

// Parse cart from customer input — e.g. '1 x2, 3 x1'
const staticData = $json.staticData;
const phone = $json.customerPhone;
const text = $json.text;
const state = staticData[phone] || {};
const itemsList = state.items_list || [];

// Parse: '1 x2, 3 x1' or '1x2 3x1'
const parsed = [];
const matches = text.matchAll(/(\d+)\s*[xX]\s*(\d+)/g);
for (const m of matches) {
  const idx = parseInt(m[1]) - 1;
  const qty = parseInt(m[2]);
  if (itemsList[idx]) {
    parsed.push({ name: itemsList[idx].item_name, qty, price: itemsList[idx].price });
  }
}

if (!parsed.length) {
  return [{ json: {
    to: phone,
    message: 'Could not parse your order. Example: `1 x2, 3 x1`\nPlease try again or reply *hi* to see the menu.'
  } }];
}

const total = parsed.reduce((sum, i) => sum + i.price * i.qty, 0);
let summary = '*Your Order:*\n';
parsed.forEach(i => { summary += `• ${i.name} x${i.qty} — PKR ${i.price * i.qty}\n`; });
summary += `\n*Total: PKR ${total}*`;

staticData[phone] = { step: 'awaiting_name', cart: parsed, total };

return [{ json: {
  to: phone,
  message: summary + '\n\nWhat\'s your name?',
  staticData
} }];

const state = $('Save Payment Choice').item.json.state;
const orderId = $json.order_id;
const phone = state.customerPhone || $('Save Payment Choice').item.json.to;

// Clear state
const staticData = $getWorkflowStaticData('global');
delete staticData[phone];

let itemList = '';
state.cart.forEach(i => { itemList += `• ${i.name} x${i.qty} — PKR ${i.price * i.qty}
`; });

const customerMsg = `✅ Order #${orderId} placed!

${itemList}
Total: PKR ${state.total}
Payment: ${state.payment_method === 'bank_transfer' ? 'Bank Transfer' : 'Cash on Delivery'}

We'll start preparing soon!`;

const adminMsg = `🆕 New Order #${orderId}

👤 ${state.customer_name}
📞 ${phone}
📍 ${state.delivery_address}

🧾 Items:
${itemList}
💰 Total: PKR ${state.total}
💳 Payment: ${state.payment_method === 'bank_transfer' ? 'Bank Transfer — awaiting screenshot' : 'Cash on Delivery'}`;

return [{ json: { orderId, phone, customerMsg, adminMsg } }];
